    jsonb_build_object('href', '/hooks', 'label', pgv.t('ops.nav_hooks'), 'icon', 'shield'),
    jsonb_build_object('href', '/docs', 'label', pgv.t('ops.nav_docs'), 'icon', 'book-open')
